wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(17539447784262561346)
,p_chart_id=>wwv_flow_imp.id(17539447648933561345)
,p_static_id=>'jumlah-penumpang-di-tiap-kereta'
,p_seq=>10
,p_name=>'Jumlah Penumpang per Hari'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    TO_CHAR(pl.tanggal_perjalanan, ''DD Mon YYYY'') AS tanggal,',
'    k.nama_kereta,',
'    COUNT(pn.penumpang_id) AS jumlah_penumpang',
'FROM tiket t',
'JOIN penumpang pn',
'    ON t.penumpang_id = pn.penumpang_id',
'JOIN perjalanan pl',
'    ON t.perjalanan_id = pl.perjalanan_id',
'JOIN kereta k',
'    ON pl.kereta_id = k.kereta_id',
'GROUP BY',
'    TO_CHAR(pl.tanggal_perjalanan, ''DD Mon YYYY''),',
'    k.nama_kereta,',
'    TRUNC(pl.tanggal_perjalanan)',
'ORDER BY',
'    TRUNC(pl.tanggal_perjalanan),',
'    k.nama_kereta;'))
,p_items_value_column_name=>'JUMLAH_PENUMPANG'
,p_items_label_column_name=>'TANGGAL'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>true
,p_items_label_position=>'auto'
,p_created_on=>wwv_flow_imp.dz('20260712113745Z')
,p_updated_on=>wwv_flow_imp.dz('20260712113848Z')
,p_created_by=>'NABILA22SI@MAHASISWA.PCR.AC.ID'
,p_updated_by=>'NABILA22SI@MAHASISWA.PCR.AC.ID'
);
